def Right_Triangle_pythagorean_theorem(leg_a, leg_b=None, hypotenuse_c=None):
    if hypotenuse_c:
        if leg_b:
            return math.sqrt(hypotenuse_c ** 2 - leg_b ** 2)
        elif leg_a:
            return math.sqrt(hypotenuse_c ** 2 - leg_a ** 2)
    else:
        return math.sqrt(leg_a ** 2 + leg_b ** 2)

